4. SERVICE IMPLEMENTÁCIÓ (srv/service.js)
```javascript
const cds = require('@sap/cds');

module.exports = class MainService extends cds.ApplicationService {
  async init() {
    this.on('approve', async (req) => {
      const { id } = req.data;
      await UPDATE('[Entitás]').set({ status: 'active' }).where({ ID: id });
      return SELECT.one.from('[Entitás]').where({ ID: id });
    });

    this.before('CREATE', '[Entitás]', (req) => {
      req.data.status = 'draft';
    });

    await super.init();
  }
};
```

