define view Z_I_[Entitás]
  as select from [alap_tábla] as db
  association [0..1] to Z_I_[MásikEntitás] as _Related
    on $projection.RelatedID = _Related.ID
{
  key db.id           as ID,
      db.name         as Name,
      db.amount       as Amount,
      db.currency     as Currency,
      db.created_at   as CreatedAt,

