2. CUBE VIEW
```cds
@Analytics.dataCategory: #CUBE
@Analytics.internalName: #LOCAL

define view Z_I_Cube_Sales
  as select from vbrp as item
  inner join vbrk as header on item.vbeln = header.vbeln
  association [0..1] to Z_I_Dim_Product  as _Product  on $projection.ProductID = _Product.ProductID
  association [0..1] to Z_I_Dim_Customer as _Customer on $projection.CustomerID = _Customer.CustomerID
  association [0..1] to I_CalendarDate   as _Date     on $projection.BillingDate = _Date.CalendarDate
{
  // Dimenziók
  key item.vbeln         as BillingDocument,
  key item.posnr         as BillingItem,

  @ObjectModel.foreignKey.association: '_Product'
  item.matnr             as ProductID,

  @ObjectModel.foreignKey.association: '_Customer'
  header.kunag           as CustomerID,

  @ObjectModel.foreignKey.association: '_Date'
  header.fkdat           as BillingDate,

  // Mértékek
  @Semantics.quantity.unitOfMeasure: 'Unit'
  @DefaultAggregation: #SUM
  item.fkimg             as BilledQuantity,
  item.vrkme             as Unit,

  @Semantics.amount.currencyCode: 'Currency'
  @DefaultAggregation: #SUM
  item.netwr             as NetAmount,
  header.waerk           as Currency,

  // Asszociációk
  _Product,
  _Customer,
  _Date
}
```

